// Parse CalDAV XML response
const xml = $input.first().json.data || '';

const tasks = [];

// Match VTODO blocks
const vtodoMatches = xml.match(/<cal:VTODO[^>]*>[\s\S]*?<\/cal:VTODO>/gi) || [];

for (const vtodo of vtodoMatches) {
  const title = vtodo.match(/<cal:SUMMARY[^>]*>([^<]*)<\/cal:SUMMARY>/i);
  const uid = vtodo.match(/<cal:UID[^>]*>([^<]*)<\/cal:UID>/i);
  const status = vtodo.match(/<cal:STATUS[^>]*>([^<]*)<\/cal:STATUS>/i);
  const due = vtodo.match(/<cal:DTEND[^>]*>([^<]*)<\/cal:DTEND>/i);
  const description = vtodo.match(/<cal:DESCRIPTION[^>]*>([^<]*)<\/cal:DESCRIPTION>/i);
  const priority = vtodo.match(/<cal:PRIORITY[^>]*>([^<]*)<\/cal:PRIORITY>/i);
  const completed = vtodo.match(/<cal:COMPLETED[^>]*>([^<]*)<\/cal:COMPLETED>/i);

  tasks.push({
    uid: uid ? uid[1] : 'unknown',
    title: title ? title[1] : 'Untitled',
    status: status ? status[1] : 'NEEDS-ACTION',
    due: due ? due[1] : null,
    description: description ? description[1] : null,
    priority: priority ? parseInt(priority[1]) : null,
    completed: completed ? completed[1] : null
  });
}

return [{ json: { tasks, count: tasks.length } }];
